-- Seed Proker
INSERT OR REPLACE INTO proker (id, judul, deskripsi, manfaat, target_sasaran) VALUES
('1', 'Desa Bersih Berkelanjutan', 'Meningkatkan kesadaran masyarakat terhadap pentingnya kebersihan lingkungan melalui kegiatan gotong royong, penyediaan sarana tempat sampah, dan pemetaan lokasi pembuangan sampah yang lebih tertata menuju desa yang bersih, sehat, dan berkelanjutan.', '["Lingkungan sehat dan nyaman", "Mencegah penyebaran penyakit", "Mengurangi pencemaran lingkungan", "Meningkatkan kesadaran dan partisipasi masyarakat"]', 'Lingkungan Desa / Masyarakat Desa'),
('2', 'Jalan Aman Bersinar', 'Meningkatkan keselamatan pengguna jalan pada malam hari melalui pemasangan mata kucing jalan dan penanda reflektif di sepanjang akses menuju Dusun 1.', '["Terpasangnya 668 mata kucing sepanjang jalan menuju Dusun 1", "Tersedianya penanda jalan menggunakan paralon reflektif", "Meningkatnya keselamatan pengguna jalan pada malam hari", "Berkurangnya risiko kecelakaan akibat minimnya penerangan dan penanda jalan", "Terciptanya lingkungan desa yang lebih aman dan nyaman bagi masyarakat"]', 'Pengguna Jalan / Masyarakat Dusun 1'),
('3', 'Teras Belajar Desa', 'Meningkatkan semangat belajar, kreativitas, dan pelestarian budaya pada anak-anak desa melalui kegiatan belajar mengajar di sekolah, Teras Belajar terbuka untuk umum, serta pelatihan tari tradisional.', '["Meningkatnya minat belajar dan literasi anak-anak", "Terlaksananya pelatihan tari tradisional bagi anak-anak desa", "Terlestarikan budaya daerah melalui kegiatan tari tradisional", "Terbangunnya hubungan positif antara mahasiswa KPPM, sekolah, dan masyarakat desa"]', 'Siswa SD, SMP, Anak-anak Desa, Masyarakat'),
('4', 'Sehat Bareng Wikara', 'Mewujudkan masyarakat desa yang sehat, aktif, dan bahagia melalui kegiatan senam, jalan santai, dan kaulihan barudak. "Bersama Sehat, Bersama Kuat, Desa Hebat!"', '["Meningkatnya kesadaran masyarakat terhadap pentingnya aktivitas fisik", "Terjalinnya kebersamaan antara mahasiswa KPPM dan masyarakat desa", "Terciptanya kegiatan rekreatif dan edukatif bagi anak-anak", "Terlestarikan kaulinan tradisional sebagai budaya lokal", "Meningkatnya partisipasi masyarakat dalam kegiatan desa", "Terwujudnya lingkungan sosial yang sehat, aktif, dan harmonis"]', 'Masyarakat Desa / Warga Dusun');
